import{_ as e}from"./plugin-vue_export-helper-c27b6911.js";import{o as a,c as r,e as h}from"./app-f07825a0.js";const o={},t=h('<h1 id="三体" tabindex="-1"><a class="header-anchor" href="#三体" aria-hidden="true">#</a> 三体</h1><h2 id="三体i" tabindex="-1"><a class="header-anchor" href="#三体i" aria-hidden="true">#</a> 三体I</h2><h3 id="序言" tabindex="-1"><a class="header-anchor" href="#序言" aria-hidden="true">#</a> 序言</h3><blockquote><p>人类之所以能够超越地球上的其它物种建立文明，主要是因为他们能够在自己的大脑中创造出现实不存在的东西，在未来，当人工智能拥有超过人类的智力时，想象力也许是我们对于它们所拥有的惟一优势。</p></blockquote><p>推荐两部科幻小说</p><ul><li><p>2001：A Space Odyssey (2001太空漫游) 目前可在腾讯视频观看电影版</p></li><li><p>Rendezvous With Rama</p></li></ul><h3 id="第一章-科学边界" tabindex="-1"><a class="header-anchor" href="#第一章-科学边界" aria-hidden="true">#</a> 第一章 科学边界</h3><blockquote><p>大部分人的人生都是偶然，是的，整个人类历史也是偶然，从石器时代到今天都没什么重大突破，真幸运。但既然是幸运总有结束的一天；</p></blockquote><h3 id="第二章-台球" tabindex="-1"><a class="header-anchor" href="#第二章-台球" aria-hidden="true">#</a> 第二章 台球</h3><blockquote><p>物理规律在时间和空间上是均匀的</p></blockquote><h3 id="第三章-射手和农场主" tabindex="-1"><a class="header-anchor" href="#第三章-射手和农场主" aria-hidden="true">#</a> 第三章 射手和农场主</h3><blockquote><p>射手假说：有一名神枪手，在一个靶子上每隔十厘米打一个洞。设想这个靶子的平面上生活着一种二维智能生物，它们中的科学家在对自己的宇宙进行观察后，发现了一个伟大的定律：“宇宙每隔10厘米，必然会有一个洞。”它们把这个神枪手一时兴起的随意行为，看成了自己宇宙中的铁律。<br> 农场主假说：一个农场里有一群火鸡，农场主每天中午11点来给它们喂食。火鸡中的一名科学家观察这个现象一年了都没有例外，于是它也发现了一个伟大的定律：“每天中午11点，就会有食欲降临。”它在感恩节早晨向火鸡们公布了这个定律，但这天上午11点没有食物降临，农场主进来把它们都捉去杀了。</p></blockquote><p>人类存在的时间只是200万年左右，宇宙存在的时间为140亿年左右，相比而言，人类科技发展时间在宇宙中的尺度是非常微小的。迄今为止人类的一切认知均建立在自己文明的经验学说之上。我们没有足够具有说服力的证据证明人类认为的科学是这个庞大的宇宙中的真理。这是人类认知上的局限性，文明的等级差距在这两个假说上体现得淋漓尽致。我们是否又只是一种三维智能生物亦或者是火鸡呢？</p><h3 id="第四章-三体、周文王、长夜" tabindex="-1"><a class="header-anchor" href="#第四章-三体、周文王、长夜" aria-hidden="true">#</a> 第四章 三体、周文王、长夜</h3><blockquote><p>第137号文明结束了</p></blockquote>',15),d=[t];function i(c,n){return a(),r("div",null,d)}const u=e(o,[["render",i],["__file","三体.html.vue"]]);export{u as default};
